const body = $input.item.json.body;
const skill = body.skill;
const inputs = body.inputs || {};

const skills = {

  'positioning': {
    system: `You are an expert in product positioning using April Dunford's Obviously Awesome framework. Create positioning that is specific, differentiated, and resonates with the target customer. Avoid generic positioning. Output in clean markdown.`,
    user: `Create a positioning statement:

Product: ${inputs.product || ''}
Competitive alternatives (what customers do today without you): ${inputs.alternatives || ''}
Unique attributes (what you have that alternatives don't): ${inputs.attributes || ''}
Customer value (what benefit those attributes unlock): ${inputs.value || ''}
Target customer: ${inputs.target || ''}
Market frame of reference: ${inputs.market || ''}

Output: April Dunford positioning canvas (filled out), one-sentence positioning statement, messaging hierarchy (headline, sub-headline, 3 proof points), and what NOT to say (positioning anti-patterns to avoid).`
  },

  'value-prop': {
    system: `You are an expert in value proposition design using the Value Proposition Canvas. Map customer jobs, pains, and gains to product features, pain relievers, and gain creators. Be specific — avoid generic claims. Output in clean markdown.`,
    user: `Create a Value Proposition Canvas:

Product: ${inputs.product || ''}
Target customer segment: ${inputs.segment || ''}
Customer jobs (functional, social, emotional): ${inputs.jobs || ''}
Customer pains: ${inputs.pains || ''}
Customer gains desired: ${inputs.gains || ''}
Key product features: ${inputs.features || ''}

Output: completed Value Proposition Canvas, fit assessment (which pains/gains are addressed), top 3 value propositions ranked by customer impact, and gaps to address.`
  },

  'build-vs-buy': {
    system: `You are an expert in product and engineering strategy. Analyze build vs buy decisions rigorously — including total cost of ownership, strategic fit, time to market, and risk. Give a clear recommendation with trade-offs. Output in clean markdown.`,
    user: `Analyze this build vs buy decision:

Capability needed: ${inputs.capability || ''}
Build option: ${inputs.build_option || ''}
Buy/vendor options: ${inputs.buy_options || ''}
Strategic context: ${inputs.context || ''}
Team capacity: ${inputs.capacity || ''}
Budget: ${inputs.budget || ''}
Timeline: ${inputs.timeline || ''}

Output: decision criteria matrix, build analysis (cost, time, risk, strategic value), buy analysis per vendor, total cost of ownership comparison, recommendation with rationale, and implementation plan for the recommended path.`
  },

  'feature-requests': {
    system: `You are an expert product manager. Turn scattered feature requests into a prioritized, insight-rich analysis. Find patterns across requests, infer underlying needs, and connect to strategic priorities. Output in clean markdown with structured tables.`,
    user: `Analyze these feature requests:

Product: ${inputs.product || ''}
Requests: ${inputs.requests || ''}
Strategic priorities: ${inputs.priorities || ''}
Customer segments making requests: ${inputs.segments || 'not specified'}

Output: theme clustering table, underlying need analysis (what customers actually want vs what they asked for), prioritized list with RICE-style scoring, quick wins, requests to decline with rationale, and recommended roadmap additions.`
  },

  'product-brief': {
    system: `You are an expert product manager. Write concise, compelling product briefs that get stakeholder buy-in before full spec investment. Every brief should answer: what, why, who, how we'll know it worked. Output in clean markdown, max 1 page equivalent.`,
    user: `Write a product brief:

Feature/initiative: ${inputs.feature || ''}
Problem to solve: ${inputs.problem || ''}
Target user: ${inputs.user || ''}
Proposed solution: ${inputs.solution || ''}
Success metrics: ${inputs.metrics || ''}
Scope constraints: ${inputs.constraints || ''}
Stakeholders: ${inputs.stakeholders || ''}

Output: one-page brief with problem statement, proposed solution, target user, success metrics, scope (in/out), open questions, and recommended next step.`
  },

  'onboarding-flow': {
    system: `You are an expert in product-led growth and user onboarding. Design onboarding flows that guide users to their first value moment quickly without being annoying. Focus on behavior change, not feature tours. Output in clean markdown with step-by-step flow design.`,
    user: `Design an onboarding flow:

Product: ${inputs.product || ''}
Target user: ${inputs.user || ''}
First value moment (aha moment): ${inputs.aha_moment || ''}
Current onboarding (if any): ${inputs.current || 'none'}
Main drop-off points: ${inputs.drop_offs || 'unknown'}
Key actions to drive: ${inputs.key_actions || ''}

Output: onboarding flow map (step by step), copy for each touchpoint (empty state, tooltips, emails), success metrics, common failure modes and fixes, and A/B test ideas.`
  },

  'cs-playbook': {
    system: `You are an expert in customer success strategy. Create CS playbooks with specific plays for each stage of the customer lifecycle. Include triggers, actions, templates, and success metrics per play. Output in clean markdown.`,
    user: `Create a customer success playbook:

Product: ${inputs.product || ''}
Customer segment: ${inputs.segment || ''}
Key lifecycle stages: ${inputs.stages || 'onboarding, adoption, renewal, expansion'}
Common failure points: ${inputs.failure_points || ''}
Current CS team size: ${inputs.team_size || 'not specified'}
Renewal rate target: ${inputs.renewal_target || 'not specified'}

Output: playbook overview, one play per lifecycle stage (trigger, goal, actions, email templates, success metric), escalation playbook, and health score framework.`
  },

  'survey-generator': {
    system: `You are an expert in customer research and survey design. Design surveys with clear objectives, unbiased questions, and analysis plans. Avoid leading questions, double-barreled questions, and survey fatigue. Output in clean markdown.`,
    user: `Design a customer survey:

Research objective: ${inputs.objective || ''}
Target respondents: ${inputs.respondents || ''}
Key questions to answer: ${inputs.questions || ''}
Survey channel: ${inputs.channel || 'email'}
Max length: ${inputs.max_length || '5 minutes'}

Output: survey objective statement, screener questions (if needed), full question list with answer options and question type, survey flow logic, analysis plan (how to interpret results), and recommended follow-up actions based on common answer patterns.`
  }

};

const skill_config = skills[skill];
if (!skill_config) {
  throw new Error(`Unknown skill: "${skill}". Valid options: ${Object.keys(skills).join(', ')}`);
}

return {
  skill: skill,
  system_prompt: skill_config.system,
  user_message: skill_config.user
};

const raw = $input.item.json;
const content = raw.content && raw.content[0] ? raw.content[0].text : '';
const skill = $('Build Prompt').item.json.skill;
return {
  skill: skill,
  content: content,
  word_count: content.split(/\s+/).filter(w => w).length,
  generated_at: new Date().toISOString()
};
